SERVICES_NEEDING_PERSONAS = ["نجارة-وديكور", "دهان", "تركيب-غاز", "صيانة-عامة", "مكافحة-حشرات"]
CITIES = ["أبوظبي", "دبي", "الشارقة", "عجمان"]

count = 0
for service_slug in SERVICES_NEEDING_PERSONAS:
    for city in CITIES:
        slug = f"{service_slug}-{city.replace(' ', '-')}"
        path = f"_configs/{slug}.json"
        if not os.path.exists(path):
            continue
        city_personas = PERSONAS.get(service_slug, {}).get(city)
        if not city_personas:
            print(f"⚠  No personas for {slug}")
            continue
        with open(path) as f:
            c = json.load(f)
        c['personas'] = city_personas
        with open(path, 'w', encoding='utf-8') as f:
            json.dump(c, f, ensure_ascii=False, indent=2)
        print(f"  ✅ {slug} — {len(city_personas)} personas")
        count += 1

print(f"\nPatched {count} configs")
